package main

import (
	"bytes"
	"encoding/binary"
	"errors"
	"flag"
	"fmt"
	"io"
	"os"
)

// Minimal ELF64 (little-endian) layout parsing using encoding/binary only.
// We patch relocation records (SHT_RELA) that reference malloc to instead
// reference wrapperSymbol (default logged_malloc) in .dynsym.

const (
	EI_CLASS      = 4
	EI_DATA       = 5
	ELFCLASS64    = 2
	ELFDATA2LSB   = 1
	ET_EXEC       = 2
	ET_DYN        = 3
	SHT_NULL      = 0
	SHT_SYMTAB    = 2
	SHT_STRTAB    = 3
	SHT_RELA      = 4
	SHT_DYNSYM    = 11
)

type elf64Ehdr struct {
	Ident     [16]byte
	Type      uint16
	Machine   uint16
	Version   uint32
	Entry     uint64
	Phoff     uint64
	Shoff     uint64
	Flags     uint32
	Ehsize    uint16
	Phentsize uint16
	Phnum     uint16
	Shentsize uint16
	Shnum     uint16
	Shstrndx  uint16
}

type elf64Shdr struct {
	Name      uint32
	Type      uint32
	Flags     uint64
	Addr      uint64
	Offset    uint64
	Size      uint64
	Link      uint32
	Info      uint32
	Addralign uint64
	Entsize   uint64
}

type elf64Sym struct {
	Name  uint32
	Info  uint8
	Other uint8
	Shndx uint16
	Value uint64
	Size  uint64
}

type elf64Rela struct {
	Offset uint64
	Info   uint64
	Addend int64
}

func rSym(info uint64) uint32  { return uint32(info >> 32) }
func rType(info uint64) uint32 { return uint32(info & 0xffffffff) }
func makeRInfo(sym uint32, typ uint32) uint64 {
	return (uint64(sym) << 32) | uint64(typ)
}

type section struct {
	idx  int
	name string
	hdr  elf64Shdr
}

func readAtFull(f *os.File, off int64, b []byte) error {
	n, err := f.ReadAt(b, off)
	if err != nil && !errors.Is(err, io.EOF) {
		return err
	}
	if n != len(b) {
		return io.ErrUnexpectedEOF
	}
	return nil
}

func cstringFrom(tab []byte, off uint32) string {
	if int(off) >= len(tab) {
		return ""
	}
	b := tab[off:]
	i := bytes.IndexByte(b, 0)
	if i < 0 {
		return ""
	}
	return string(b[:i])
}

func main() {
	flag.Usage = func() {
		fmt.Fprintf(os.Stderr, "usage: %s <input_elf> <output_elf> [wrapper_symbol]\n", os.Args[0])
	}
	flag.Parse()
	args := flag.Args()
	if len(args) != 2 && len(args) != 3 {
		flag.Usage()
		os.Exit(2)
	}
	inPath, outPath := args[0], args[1]
	wrapperSymbol := "logged_malloc"
	if len(args) == 3 {
		wrapperSymbol = args[2]
	}

	in, err := os.Open(inPath)
	if err != nil {
		fmt.Fprintf(os.Stderr, "error: open input: %v\n", err)
		os.Exit(1)
	}
	defer in.Close()

	st, err := in.Stat()
	if err != nil {
		fmt.Fprintf(os.Stderr, "error: stat input: %v\n", err)
		os.Exit(1)
	}
	if st.Size() < 64 {
		fmt.Fprintf(os.Stderr, "error: input too small to be ELF64\n")
		os.Exit(1)
	}

	// Read ELF header (64 bytes for ELF64)
	var eh elf64Ehdr
	if err := binary.Read(io.NewSectionReader(in, 0, 1<<63-1), binary.LittleEndian, &eh); err != nil {
		fmt.Fprintf(os.Stderr, "error: read ELF header: %v\n", err)
		os.Exit(1)
	}
	if eh.Ident[0] != 0x7f || eh.Ident[1] != 'E' || eh.Ident[2] != 'L' || eh.Ident[3] != 'F' {
		fmt.Fprintf(os.Stderr, "error: not an ELF file\n")
		os.Exit(1)
	}
	if eh.Ident[EI_CLASS] != ELFCLASS64 {
		fmt.Fprintf(os.Stderr, "error: expected ELFCLASS64, got %d\n", eh.Ident[EI_CLASS])
		os.Exit(1)
	}
	if eh.Ident[EI_DATA] != ELFDATA2LSB {
		fmt.Fprintf(os.Stderr, "error: expected little-endian ELF, got data=%d\n", eh.Ident[EI_DATA])
		os.Exit(1)
	}
	if eh.Type != ET_EXEC && eh.Type != ET_DYN {
		fmt.Fprintf(os.Stderr, "error: expected ET_EXEC or ET_DYN, got %d\n", eh.Type)
		os.Exit(1)
	}
	if eh.Shoff == 0 || eh.Shnum == 0 {
		fmt.Fprintf(os.Stderr, "error: missing section headers\n")
		os.Exit(1)
	}
	if eh.Shentsize != uint16(binary.Size(elf64Shdr{})) {
		fmt.Fprintf(os.Stderr, "error: unexpected section header entry size %d\n", eh.Shentsize)
		os.Exit(1)
	}

	// Read section headers
	shdrs := make([]elf64Shdr, int(eh.Shnum))
	shBytes := make([]byte, int(eh.Shentsize)*int(eh.Shnum))
	if err := readAtFull(in, int64(eh.Shoff), shBytes); err != nil {
		fmt.Fprintf(os.Stderr, "error: read section headers: %v\n", err)
		os.Exit(1)
	}
	for i := 0; i < int(eh.Shnum); i++ {
		var sh elf64Shdr
		off := i * int(eh.Shentsize)
		if err := binary.Read(bytes.NewReader(shBytes[off:off+int(eh.Shentsize)]), binary.LittleEndian, &sh); err != nil {
			fmt.Fprintf(os.Stderr, "error: parse section header %d: %v\n", i, err)
			os.Exit(1)
		}
		shdrs[i] = sh
	}
	if int(eh.Shstrndx) >= len(shdrs) {
		fmt.Fprintf(os.Stderr, "error: shstrndx out of range\n")
		os.Exit(1)
	}

	// Read section header string table
	shstr := shdrs[eh.Shstrndx]
	if shstr.Type != SHT_STRTAB {
		fmt.Fprintf(os.Stderr, "error: shstr section not STRTAB\n")
		os.Exit(1)
	}
	shstrTab := make([]byte, int(shstr.Size))
	if err := readAtFull(in, int64(shstr.Offset), shstrTab); err != nil {
		fmt.Fprintf(os.Stderr, "error: read shstrtab: %v\n", err)
		os.Exit(1)
	}

	sections := make([]section, len(shdrs))
	for i := range shdrs {
		sections[i] = section{idx: i, name: cstringFrom(shstrTab, shdrs[i].Name), hdr: shdrs[i]}
	}

	// Find .dynsym and .dynstr
	var dynsym *section
	var dynstr *section
	for i := range sections {
		s := &sections[i]
		if s.hdr.Type == SHT_DYNSYM || s.name == ".dynsym" {
			// prefer the named one
			if dynsym == nil || s.name == ".dynsym" {
				dynsym = s
			}
		}
		if s.name == ".dynstr" {
			dynstr = s
		}
	}
	if dynsym == nil || dynstr == nil {
		fmt.Fprintf(os.Stderr, "error: missing .dynsym/.dynstr\n")
		os.Exit(1)
	}

	// Load dynstr
	dynStrTab := make([]byte, int(dynstr.hdr.Size))
	if err := readAtFull(in, int64(dynstr.hdr.Offset), dynStrTab); err != nil {
		fmt.Fprintf(os.Stderr, "error: read .dynstr: %v\n", err)
		os.Exit(1)
	}
	// Load dynsym
	if dynsym.hdr.Entsize == 0 {
		dynsym.hdr.Entsize = uint64(binary.Size(elf64Sym{}))
	}
	if dynsym.hdr.Entsize != uint64(binary.Size(elf64Sym{})) {
		fmt.Fprintf(os.Stderr, "error: unexpected .dynsym entsize=%d\n", dynsym.hdr.Entsize)
		os.Exit(1)
	}
	if dynsym.hdr.Size%dynsym.hdr.Entsize != 0 {
		fmt.Fprintf(os.Stderr, "error: .dynsym size not multiple of entsize\n")
		os.Exit(1)
	}
	symCount := int(dynsym.hdr.Size / dynsym.hdr.Entsize)
	dynSymBytes := make([]byte, int(dynsym.hdr.Size))
	if err := readAtFull(in, int64(dynsym.hdr.Offset), dynSymBytes); err != nil {
		fmt.Fprintf(os.Stderr, "error: read .dynsym: %v\n", err)
		os.Exit(1)
	}
	nameBySym := make([]string, symCount)
	for i := 0; i < symCount; i++ {
		var sym elf64Sym
		off := i * int(dynsym.hdr.Entsize)
		if err := binary.Read(bytes.NewReader(dynSymBytes[off:off+int(dynsym.hdr.Entsize)]), binary.LittleEndian, &sym); err != nil {
			fmt.Fprintf(os.Stderr, "error: parse dynsym %d: %v\n", i, err)
			os.Exit(1)
		}
		nameBySym[i] = cstringFrom(dynStrTab, sym.Name)
	}

	mallocSym := -1
	wrapperSym := -1
	for i, n := range nameBySym {
		if n == "malloc" {
			mallocSym = i
		}
		if n == wrapperSymbol {
			wrapperSym = i
		}
	}
	if wrapperSym < 0 {
		fmt.Fprintf(os.Stderr, "error: wrapper symbol not found in .dynsym: %s\n", wrapperSymbol)
		os.Exit(1)
	}
	if mallocSym < 0 {
		// still possible relocations reference malloc via versioned name, but readelf output suggests plain malloc.
		fmt.Fprintf(os.Stderr, "error: symbol not found in .dynsym: malloc\n")
		os.Exit(1)
	}

	// Copy input -> output first, then patch in-place by writing specific bytes.
	out, err := os.OpenFile(outPath, os.O_CREATE|os.O_TRUNC|os.O_WRONLY, 0755)
	if err != nil {
		fmt.Fprintf(os.Stderr, "error: create output: %v\n", err)
		os.Exit(1)
	}
	defer out.Close()
	if _, err := in.Seek(0, io.SeekStart); err != nil {
		fmt.Fprintf(os.Stderr, "error: seek input: %v\n", err)
		os.Exit(1)
	}
	if _, err := io.Copy(out, in); err != nil {
		fmt.Fprintf(os.Stderr, "error: copy input to output: %v\n", err)
		os.Exit(1)
	}

	// Ensure header prefix (first 64 bytes) identical by design (we copied whole file).
	// Now patch relocation sections.
	patched := 0
	for i := range sections {
		s := &sections[i]
		if s.hdr.Type != SHT_RELA {
			continue
		}
		// Only relocation sections whose symbol table is .dynsym (link index)
		if int(s.hdr.Link) != dynsym.idx {
			continue
		}
		entsize := s.hdr.Entsize
		if entsize == 0 {
			entsize = uint64(binary.Size(elf64Rela{}))
		}
		if entsize != uint64(binary.Size(elf64Rela{})) {
			continue
		}
		if s.hdr.Size%entsize != 0 {
			continue
		}
		relaCount := int(s.hdr.Size / entsize)
		buf := make([]byte, int(s.hdr.Size))
		if err := readAtFull(out, int64(s.hdr.Offset), buf); err != nil {
			fmt.Fprintf(os.Stderr, "error: read relocation section %s: %v\n", s.name, err)
			os.Exit(1)
		}
		for j := 0; j < relaCount; j++ {
			entOff := j * int(entsize)
			var rela elf64Rela
			if err := binary.Read(bytes.NewReader(buf[entOff:entOff+int(entsize)]), binary.LittleEndian, &rela); err != nil {
				fmt.Fprintf(os.Stderr, "error: parse rela %s[%d]: %v\n", s.name, j, err)
				os.Exit(1)
			}
			sym := int(rSym(rela.Info))
			typ := rType(rela.Info)
			if sym < 0 || sym >= len(nameBySym) {
				continue
			}
			if nameBySym[sym] != "malloc" {
				continue
			}

			oldInfo := rela.Info
			rela.Info = makeRInfo(uint32(wrapperSym), typ)

			// Write only the Info field back (offset+8) to minimize modifications.
			infoOffInFile := int64(s.hdr.Offset) + int64(entOff) + 8
			var tmp [8]byte
			binary.LittleEndian.PutUint64(tmp[:], rela.Info)
			if _, err := out.WriteAt(tmp[:], infoOffInFile); err != nil {
				fmt.Fprintf(os.Stderr, "error: patch write %s[%d]: %v\n", s.name, j, err)
				os.Exit(1)
			}
			patched++
			fmt.Fprintf(os.Stderr, "patched relocation section=%s index=%d r_offset=0x%x r_type=%d r_sym:%d(%s)->%d(%s) old_r_info=0x%x new_r_info=0x%x\n",
				s.name, j, rela.Offset, typ, sym, "malloc", wrapperSym, wrapperSymbol, oldInfo, rela.Info)
		}
	}

	if patched == 0 {
		fmt.Fprintf(os.Stderr, "error: no applicable relocations found targeting symbol malloc\n")
		os.Exit(1)
	}

	if err := out.Close(); err != nil {
		fmt.Fprintf(os.Stderr, "error: close output: %v\n", err)
		os.Exit(1)
	}
	if err := os.Chmod(outPath, 0755); err != nil {
		fmt.Fprintf(os.Stderr, "error: chmod output: %v\n", err)
		os.Exit(1)
	}
	fmt.Fprintf(os.Stderr, "done: patched %d relocation(s) from malloc to %s\n", patched, wrapperSymbol)
}
